.pill-list .elementor-icon-list-items {
    display: flex;
    flex-wrap: wrap;
    gap: 14px;
}

.pill-list .elementor-icon-list-item {
    width: auto;
}

.pill-list .elementor-icon-list-text {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 10px 22px;
    border-radius: 999px;
    border: 1px solid rgba(255,255,255,0.35);
    background: rgba(0,0,0,0.35); /* glass effect */
    color: white;
    font-size: 16px;
    line-height: 1;
    transition: all 0.25s ease;
}

/* Hover Effect */
.pill-list .elementor-icon-list-item:hover .elementor-icon-list-text {
    background: rgba(255,255,255,0.15);
    border-color: rgba(255,255,255,0.6);
    transform: translateY(-1px);
}

